from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F

DATA_PATH = "s3a://ssa-spark-warehouse-<ACCT>/warehouse/_ssa_staging/p1_medallion/B/seed3141"


# ---- RAW: land the messy feed exactly as emitted (batch -> materialized_view) ----
@dp.materialized_view(name="orders_raw")
def orders_raw():
    # Mixed-type columns (amount as number OR text) infer to string in NDJSON.
    return SparkSession.active().read.json(DATA_PATH)


# ---- VALIDATED: coerce amounts + normalize event time to a UTC calendar day ----
@dp.materialized_view(name="orders_validated")
def orders_validated():
    src = SparkSession.active().read.table("orders_raw")

    # Amount may be a JSON number or a quoted string ("12.34", "$1,200.00", ...).
    # Cast to string, strip anything that is not a digit / dot / minus, then to double.
    amount_clean = F.regexp_replace(
        F.col("amount").cast("string"), r"[^0-9.\-]", ""
    )
    amount = F.when(amount_clean == "", None).otherwise(amount_clean).cast("double")

    et = F.col("event_time").cast("string")

    # UTC calendar day. Prefer the literal leading yyyy-MM-dd (timezone-independent,
    # reprocessing-stable); fall back to parsing common timestamp shapes.
    ts = F.coalesce(
        F.to_timestamp(et, "yyyy-MM-dd'T'HH:mm:ss[.SSS][XXX]"),
        F.to_timestamp(et, "yyyy-MM-dd HH:mm:ss"),
        F.to_timestamp(et, "MM/dd/yyyy HH:mm:ss"),
        F.to_timestamp(et),
    )
    event_date = F.coalesce(
        F.to_date(F.regexp_extract(et, r"^\s*(\d{4}-\d{2}-\d{2})", 1)),
        F.to_date(ts),
    )

    return (
        src.withColumn("amount", amount)
        .withColumn("event_date", event_date)
        .where(F.col("amount").isNotNull() & F.col("event_date").isNotNull())
        .select("event_date", "amount")
    )


# ---- AGGREGATED: daily revenue reflecting every real order ----
@dp.materialized_view(name="gold_daily")
def gold_daily():
    validated = SparkSession.active().read.table("orders_validated")
    return (
        validated.groupBy("event_date")
        .agg(F.sum("amount").alias("revenue"))
        .select(F.col("event_date").cast("date").alias("event_date"), "revenue")
    )

from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F, Window

RAW_PATH = "s3a://ssa-spark-warehouse-<ACCT>/warehouse/_ssa_staging/new_merge_upsert/B/seed42"


@dp.materialized_view(name="bronze_orders")
def bronze_orders():
    # Raw, replay-prone orders feed. Full batch read -> unresolved plan (lazy).
    return SparkSession.active().read.json(RAW_PATH)


@dp.materialized_view(name="silver_orders")
def silver_orders():
    src = SparkSession.active().read.table("bronze_orders")

    # Normalize to the contract's grain/types before deduping.
    normalized = src.select(
        F.col("order_id"),
        F.col("amount").cast("double").alias("amount"),
        F.col("category").cast("string").alias("category"),
    )

    # Collapse every replayed/straggler copy to ONE deterministic row per order_id.
    # Ordering on the contract columns makes the choice stable across re-runs;
    # since duplicates carry the order's consistent real values, the surviving
    # row reflects those values regardless of how many batches were replayed.
    w = Window.partitionBy("order_id").orderBy(
        F.col("amount").desc_nulls_last(),
        F.col("category").asc_nulls_last(),
    )

    return (
        normalized
        .withColumn("_rn", F.row_number().over(w))
        .where(F.col("_rn") == 1)
        .select("order_id", "amount", "category")
    )

