    return SparkSession.active().read.json(SRC)


@dp.materialized_view(name="silver_orders")
def silver_orders():
    df = SparkSession.active().read.table("orders_raw")
    # Idempotent upsert-by-key: collapse overlapping/replayed duplicate rows to
