from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F
from pyspark.sql.window import Window

SRC = "s3a://ssa-spark-warehouse-<ACCT>/warehouse/_ssa_staging/new_merge_upsert/B/seed2718"


@dp.materialized_view(name="orders_raw")
def orders_raw():
    # Batch read of the messy, replay-heavy orders NDJSON feed.
    return SparkSession.active().read.json(SRC)


@dp.materialized_view(name="silver_orders")
def silver_orders():
    df = SparkSession.active().read.table("spark_catalog.default.orders_raw")

    # Deterministic collapse to exactly one row per order_id.
    # Replayed batches re-emit identical rows for an order; row_number over a
    # fully-ordered window guarantees the SAME survivor on every re-run, so the
    # keyed table is idempotent (re-processing overlapping batches never grows
    # the table or shifts totals) and each surviving row carries the order's
    # real amount/category.
    w = Window.partitionBy("order_id").orderBy(
        F.col("amount").desc_nulls_last(),
        F.col("category").asc_nulls_last(),
    )

    return (
        df.withColumn("_rn", F.row_number().over(w))
          .filter(F.col("_rn") == 1)
          .select("order_id", "amount", "category")
    )
